import { jsPDF } from "jspdf";

const LOGO_BASE64 = "";
const FIRMA_BASE64 = "";

export interface CertificateData {
  nombre: string;
  cedula: string;
  puntaje: number;
  fecha: string;
}

export function generateCertificate(data: CertificateData) {
  const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });

  const W = 297;
  const H = 210;

  // Fondo blanco
  doc.setFillColor(255, 255, 255);
  doc.rect(0, 0, W, H, "F");

  // Borde exterior verde oscuro
  doc.setDrawColor(27, 94, 32);
  doc.setLineWidth(5);
  doc.rect(6, 6, W - 12, H - 12, "S");

  // Borde interior verde claro
  doc.setDrawColor(76, 175, 80);
  doc.setLineWidth(1.5);
  doc.rect(11, 11, W - 22, H - 22, "S");

  // Franja superior verde
  doc.setFillColor(27, 94, 32);
  doc.rect(6, 6, W - 12, 32, "F");

  // Franja inferior verde
  doc.setFillColor(27, 94, 32);
  doc.rect(6, H - 36, W - 12, 30, "F");

  // Logo hospital
  try {
    doc.addImage("data:image/png;base64," + LOGO_BASE64, "PNG", 13, 8, 110, 28);
  } catch (e) {
    console.error("Error logo", e);
  }

  // NIT esquina superior derecha
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(9);
  doc.setFont("helvetica", "bold");
  doc.text("NIT: 807004393-5", W - 16, 17, { align: "right" });
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8);
  doc.text("Los Patios, Norte de Santander", W - 16, 24, { align: "right" });
  doc.text("Colombia", W - 16, 30, { align: "right" });

  // Título principal
  doc.setTextColor(27, 94, 32);
  doc.setFontSize(26);
  doc.setFont("helvetica", "bold");
  doc.text("CERTIFICADO DE INDUCCIÓN", W / 2, 57, { align: "center" });

  // Subtítulo
  doc.setFontSize(13);
  doc.setTextColor(50, 50, 50);
  doc.setFont("helvetica", "bold");
  doc.text("SARLAFT – FPADM", W / 2, 66, { align: "center" });

  // Líneas decorativas
  doc.setDrawColor(27, 94, 32);
  doc.setLineWidth(1);
  doc.line(55, 70, W - 55, 70);
  doc.setDrawColor(76, 175, 80);
  doc.setLineWidth(0.4);
  doc.line(55, 72, W - 55, 72);

  // Texto "Se certifica que"
  doc.setFontSize(11);
  doc.setTextColor(90, 90, 90);
  doc.setFont("helvetica", "italic");
  doc.text("Se certifica que el/la colaborador/a:", W / 2, 83, { align: "center" });

  // Nombre
  doc.setFontSize(21);
  doc.setTextColor(27, 94, 32);
  doc.setFont("helvetica", "bold");
  doc.text(data.nombre.toUpperCase(), W / 2, 95, { align: "center" });

  // Línea bajo nombre
  doc.setDrawColor(200, 200, 200);
  doc.setLineWidth(0.4);
  doc.line(65, 98, W - 65, 98);

  // Cédula
  doc.setFontSize(10);
  doc.setTextColor(100, 100, 100);
  doc.setFont("helvetica", "normal");
  doc.text("Identificado/a con C.C. No. " + data.cedula, W / 2, 104, { align: "center" });

  // Cuerpo
  doc.setFontSize(10.5);
  doc.setTextColor(55, 55, 55);
  doc.setFont("helvetica", "normal");
  doc.text("Ha completado satisfactoriamente el programa de Inducción y Reinducción en el Sistema de Administración del", W / 2, 113, { align: "center" });
  doc.text("Riesgo de Lavado de Activos, Financiación del Terrorismo y de la Proliferación de Armas de Destrucción Masiva", W / 2, 119, { align: "center" });
  doc.setFont("helvetica", "bold");
  doc.setTextColor(27, 94, 32);
  doc.text("(SARLAFT–FPADM), obteniendo un puntaje de " + data.puntaje + "% — APROBADO", W / 2, 127, { align: "center" });

  // Fecha
  doc.setFont("helvetica", "italic");
  doc.setFontSize(9.5);
  doc.setTextColor(110, 110, 110);
  doc.text("Expedido en Los Patios, el " + data.fecha, W / 2, 134, { align: "center" });

  // Firma imagen
  try {
    doc.addImage("data:image/jpeg;base64," + FIRMA_BASE64, "JPEG", W / 2 - 18, 138, 36, 17);
  } catch (e) {
    console.error("Error firma", e);
  }

  // Línea firma
  doc.setDrawColor(27, 94, 32);
  doc.setLineWidth(0.6);
  doc.line(W / 2 - 45, 157, W / 2 + 45, 157);

  // Nombre y cargo firmante
  doc.setFontSize(9.5);
  doc.setTextColor(27, 94, 32);
  doc.setFont("helvetica", "bold");
  doc.text("Martha Gómez", W / 2, 162, { align: "center" });
  doc.setFont("helvetica", "normal");
  doc.setTextColor(80, 80, 80);
  doc.text("Oficial de Cumplimiento SARLAFT", W / 2, 167, { align: "center" });
  doc.text("Hospital Local Municipio de Los Patios — E.S.E.", W / 2, 172, { align: "center" });

  // Franja inferior texto
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("Este certificado es válido como constancia de cumplimiento normativo del programa de inducción SARLAFT–FPADM.", W / 2, H - 22, { align: "center" });
  doc.text("Puntaje: " + data.puntaje + "% | Fecha: " + data.fecha + " | Hospital Local Municipio de Los Patios E.S.E.", W / 2, H - 16, { align: "center" });

  doc.save("Certificado_SARLAFT_" + data.nombre.replace(/\s+/g, "_") + ".pdf");
}
